const Q_ACCOUNTS_1999=[{"id": "objective>Accounts>1999>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Accrual concept stipulates that?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">revenue should be recognized when it is earned</div>", "<div style=\"font-family:Cambria;font-size:17px;\">costs should be recognized when the expenditure is paid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">revenue should be recognized only when cash is paid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">costs should be recognized when the are incurred</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Accrual concept means that revenues and expenses are recognized as they are earned or incurred and not when money is received or paid. The profit of a business will show the difference between the revenues and expenses.</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS"}, {"id": "objective>Accounts>1999>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basic role of accounting is to?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">detect fraud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attest to finacial statements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">measure performance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect sharehlders</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The basic role of accounting is to measure the performance of a business. It provides the necessary financial information that allows managers, investors, and others to make decisions about the allocation of resources. While accounting can help in detecting fraud, attesting to financial statements, and protecting shareholders, these are not its primary role.</div>", "topic": "INTRODUCTION TO ACCOUNTING : USERS OF ACCOUNTING & ROLES OF ACCOUNTING"}, {"id": "objective>Accounts>1999>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The need for changes in accounting theory in Nigeria was influenced by the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dynamics of commercialization and privatization policies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">growth in size of business units</div>", "<div style=\"font-family:Cambria;font-size:17px;\">introduction of the structural adjustment programme</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> inconvertibility of the nation's currency</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The need for changes in accounting theory in Nigeria was influenced by the dynamics of commercialization and privatization policies. Commercialization and privatization policies led to the emergence of new business structures and practices, which necessitated changes in accounting theory to accommodate these changes.</div>", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING"}, {"id": "objective>Accounts>1999>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A bookkeeping error occurs when there is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> a deliberate manipulation of records</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unintentional correct posting in the ledger</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> intentional failure to record transactions completely</div>", "<div style=\"font-family:Cambria;font-size:17px;\">incorrect records and oversights that are not intended</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An acounting error is a non-fradulent error in double entry bookeeping transactions. Data entry accounting errors occur when inaccurate data or information is entered in the books.</div>", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE"}, {"id": "objective>Accounts>1999>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a proprietor withdraws cash from the business for private use, he?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debits cash account and credits drawings account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">credits cash account and debits bank account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debits bank account and credits drawings account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">credits cash account and debits drawings account</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Withdrawal of any amount in cash or kind from the enterprise for personal use by the proprietor is termed as Drawings: The drawings account will be debited and the cash or goods withdrawn will be debited.</div>", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS"}, {"id": "objective>Accounts>1999>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A basic unifying concept in accounting implies that?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">where creditors'account is zero, the assets are equal to the owners' equity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there should be a balance in the creditors' account in order to measure total assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">revenues should be supported by invested and owners'capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total assets can be less than liabilities and equity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equation thus becomes A - L -E = 0 ( zero). When the debits equals the total credits for each account, then the equation balances.</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION"}, {"id": "objective>Accounts>1999>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A source document for the sales day book is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a requisition form</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an invoice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a customer advice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a credit advice</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sales day book can be classified as a manual ledger documenting detailed information on a sales made by a saleperson to the customers for a given business day. For example, it would document information on customer name, invoice date, unique invoice number, and the amount of credit sale made on that day.</div>", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT"}, {"id": "objective>Accounts>1999>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a cash book, the opening balance was N7,600, closing balance N9,200 and the total cash received during the period was N18,000. What was the amount of cash paid out during the period?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N8,900</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N9,800</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N14,600</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N16,400</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cash book <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> #</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">#</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Bal b/f</td><td style=\"border:1px solid black;text-align:center;\"> 7600</td><td style=\"border:1px solid black;text-align:center;\"> Bal c/d</td><td style=\"border:1px solid black;text-align:center;\"> 9200</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Total cash received</td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"text-decoration:underline;\"> 18000 </span></td><td style=\"border:1px solid black;text-align:center;\"> Cash paid out ( missing figure)</td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"text-decoration:underline;\"> 16400 </span></td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> 25600</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">25600</td></tr></table></div></div>", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK"}, {"id": "objective>Accounts>1999>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the total discount allowed in a cash book was N230 and the total discount received was N255, which of the following is true concerning the two discounts?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They must be balanced in the cash book and the difference taken to the debtors ledger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They must be balanced in the cash book and the difference taken to the trial balance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They should not be balanced in the cash book before being taking to the trial balance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They should not appear in the trial balance as they were already either received or paid out</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cash book is the book of prime entry for discounts. Total of discounts columns are used to post to ledgers.</div>", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED"}, {"id": "objective>Accounts>1999>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following bank reconciliation items should not be added or subtracted from the bank statement balance to determine the adjusted cash balance?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Outstanding cheques</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bank service charges</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Deposit in the mail not yet received by the bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bank error, charging a company for another company's cheque</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bank service charges are not added or subtracted from the bank statement balance to determine the adjusted cash balance. Instead, they are subtracted from the book balance. This is because bank service charges are expenses incurred by the business and are recorded in the company's cash book when the bank statement is received. The other options like outstanding cheques, deposits in transit, and bank errors are adjustments made to the bank statement balance to reconcile it with the book balance.</div>", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREENMENT BETWEEN CASH BOOK & BANK STATEMENT"}, {"id": "objective>Accounts>1999>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fixed amount of money given to a petty cashier at the beginning of a period is called?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> imprest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">petty cash</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> float</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash advance</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Imprest is used by a business for small items of expenditure, and restored to fixed amount periodically. Hence,a petty cash book is kept on the imprest amount.</div>", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE"}, {"id": "objective>Accounts>1999>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A provision for bad debt account had N3,800 at the beginning of the year and N4,220 at the close of the year. If bad debts are calculated at the rate of <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span>% of annual sales, what was the credit sales for the period?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N2,100,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N844,400</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> N84,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N500,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bal c/d - Bal b/f = Bad debts <br/> Bad debts = 4,220 - 3,800 <br/> = 420 <br/>  <br/> Credit sales = bad debt written off/rate of bad debts <br/> 1/2% = 0.005 <br/>  <br/> Credit sales = 420/0.005 <br/> = 84,000</div>", "topic": "RESERVES AND PROVISIONS : BAD DEBTS AND PROVISIONS FOR DOUBTFUL DEBTS"}, {"id": "objective>Accounts>1999>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Asa Company bought a vehicle worth N20,000 and the vehicle is to be depreciated at 5%. Using the reducing balance method of depreciation, what would be the value of the asset after 3 years?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N19,000.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N18,050.50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N17,147.50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N16,290.13</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1st year = 20,000  x 95/100 <br/> = 19,000 <br/>  <br/> 2nd year = 19000  x 95/100 <br/> = 18,050 <br/>  <br/> 3rd year = 18,050  x 95/100 <br/> = #17,147.50</div>", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION"}, {"id": "objective>Accounts>1999>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use  the information below to answer questions below <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> #</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Capital: Opening balance</td><td style=\"border:1px solid black;text-align:center;\"> 307 000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Closing balance</td><td style=\"border:1px solid black;text-align:center;\"> 342 000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Net profit for the period</td><td style=\"border:1px solid black;text-align:center;\"> 121 600</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Opening stock </td><td style=\"border:1px solid black;text-align:center;\"> 98 800</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 706 000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Carriage inwards</td><td style=\"border:1px solid black;text-align:center;\"> 17 500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cost of goods sold</td><td style=\"border:1px solid black;text-align:center;\"> 740700</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Total selling, general and administration expenses</td><td style=\"border:1px solid black;text-align:center;\"> 526 000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Discount received</td><td style=\"border:1px solid black;text-align:center;\"> 9 650</td></tr></table></div> <br/>  <br/> what is the closing stock for the period?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#69, 300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#81, 300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#81, 600</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#106, 400</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cost of goods sold = opening stock + purchases + carriage inwards - closing stock <br/> 740,700 = 98,000 + 706,000 + 17500 - closing stock <br/> 740,700 = 822,300 - Closing stock <br/> Closing stock = 822,300 - 740,700 <br/> = #81,600</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES"}, {"id": "objective>Accounts>1999>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use  the information below to answer questions below <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> #</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Capital: Opening balance</td><td style=\"border:1px solid black;text-align:center;\"> 307 000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Closing balance</td><td style=\"border:1px solid black;text-align:center;\"> 342 000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Net profit for the period</td><td style=\"border:1px solid black;text-align:center;\"> 121 600</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Opening stock </td><td style=\"border:1px solid black;text-align:center;\"> 98 800</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 706 000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Carriage inwards</td><td style=\"border:1px solid black;text-align:center;\"> 17 500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cost of goods sold</td><td style=\"border:1px solid black;text-align:center;\"> 740700</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Total selling, general and administration expenses</td><td style=\"border:1px solid black;text-align:center;\"> 526 000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Discount received</td><td style=\"border:1px solid black;text-align:center;\"> 9 650</td></tr></table></div> <br/> Calculate the gross profit for the period</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#535,650</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#628,300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#637,950</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#647,600</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gross profit + Discount received - expenses = Net profit <br/> Gross profit + 9,650 - 526,000 = 121,600 <br/>  Gross profit = 121,600 + 516,350 <br/> = #637,950</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT"}, {"id": "objective>Accounts>1999>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Chibuike bought 36 notebooks at N10 each from John and was given a trade discount of 5%. In addition, he was offered 1% cash discount which he took advantage of. How much did Chibuike pay?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> N338.58</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N342.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N345.42</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N360,00</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total price = 10  x 36  <br/> = 360 <br/>  <br/> Trade discount = 5/100  x 360 <br/> = 18 <br/>  <br/> Net price = 360 - 18 <br/> = 342 <br/>  <br/> Cash discount  = 342  x 1/100 <br/> = 3.42 <br/>  <br/> Net price = 342 - 3.42 <br/> = 338.58</div>", "topic": "ACCOUNTING RATIO ( 1) : MARK UP AND MARGIN"}, {"id": "objective>Accounts>1999>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Depreciation on a particular piece of machinery was N2,700 during the fifth year of its service life and N4,050 during the sixth year. The logical explanation for this is that?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an addition was made to the asset during the sixth year</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the estimate of salvage value on this equipment was decreased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a unit-of-output method of depreciation was used during the sixth year</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the estimate remaining service life of the assets was increased at the beginning of the sixth year</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The unit-of-output method of depreciation is a depreciation method that allocates the cost of an asset over its useful life based on the number of units it produces or the hours it operates, rather than the number of years it is in use. In this case, the machinery might have produced more units or operated for more hours in the sixth year than in the fifth year, resulting in a higher depreciation expense.</div>", "topic": "DEPRECIATION OF FIXED ASSETS : CAUSES AND ELEMENTS OF DEPRECIATION"}, {"id": "objective>Accounts>1999>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main features of the single system are that?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">books of accounts are not maintained and business relies only on bank statement</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> the journal records are absent and only the main ledger is kept 7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there are incomplete classifications and recording procedures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">only credit sales transactions and credit purchase are recorded</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main characteristics or features of single entry bookeeping system are: <br/> - lacks fixed rules and principles <br/> - incomplete acounting system <br/> - lacks arithmetical accuracy <br/> - no final accounts <br/> - no true profit or loss <br/> - no disclosure of financial position <br/> - suitable for small business firms</div>", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : INTRODUCTION AND ADVANTAGES"}, {"id": "objective>Accounts>1999>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The principal function of a sales ledger control account is to?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">serve as internal check and provide quick information for the preparation of interim financial statements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">serve as external check and provide quick information for the preparation of interim financial statements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide quick information for the preparation of customers' statement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide information for the control of salesmen's activities</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A sales ledger control account is a part of the double entry bookkeeping system and is used as an internal check mechanism. It provides a summary of sales on credit and is used to quickly gather information for the preparation of interim financial statements. It does not serve as an external check, nor does it provide information for the control of salesmen's activities or the preparation of customers' statements.</div>", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT"}, {"id": "objective>Accounts>1999>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In dealing with incomplete records, fixed assets are posted to?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">opening profit and loss as brought forward figures</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> closing balance sheet as carried forward figures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">closing balance sheets as brought forward figures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">closing profit and loss as brought forward figures</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In dealing with incomplete records, fixed assets are posted to the closing balance sheet as carried forward figures. This is because fixed assets are long-term assets that a company plans to use in its operations over a long period of time, and they are carried forward to the next accounting period. They are not posted to the opening profit and loss as brought forward figures, closing balance sheets as brought forward figures, or closing profit and loss as brought forward figures.</div>", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : PREPARATION OF FINAL ACCOUNTS FROM INCOMPLETE RECORDS"}, {"id": "objective>Accounts>1999>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information to answer the question below <br/> Aminu and Sons credit purchases (Extract) as at February 1996. <br/>  <br/> Feb 1Credit balances---------------- 40, 000 <br/> Debit balances -----------------------1, 000 <br/> Feb 28 Purchases journal totals--------------------- 500,000 <br/> Returns outwards journal totals ----------------------50,000 <br/> Cheques paid to suppliers -------------------400,000 <br/> Promissory notes sent to suppliers------------- 30,000 <br/> Discount received from suppliers............................8,000 <br/> Credit balance in the purchases ledger set off against debit balances in the sales ledger-------2,000 <br/>  <br/> The Total for the purchases ledger control account is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N 480,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N490,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N 500,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N540,000</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trade Payable Account <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> #</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">#</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Bal b/f </td><td style=\"border:1px solid black;text-align:center;\"> 1000</td><td style=\"border:1px solid black;text-align:center;\"> Bal b/f</td><td style=\"border:1px solid black;text-align:center;\">40000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Returns outwards</td><td style=\"border:1px solid black;text-align:center;\"> 50000</td><td style=\"border:1px solid black;text-align:center;\"> Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 500000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cheques paid to supplier</td><td style=\"border:1px solid black;text-align:center;\"> 400000</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Promissory note</td><td style=\"border:1px solid black;text-align:center;\"> 30000</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Discount received from suppliers</td><td style=\"border:1px solid black;text-align:center;\">8000</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Set off</td><td style=\"border:1px solid black;text-align:center;\"> 2000</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Bal c/d </td><td style=\"border:1px solid black;text-align:center;\"><span style=\"text-decoration:underline;\"> 49000 </span></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Total (missing figure)</td><td style=\"border:1px solid black;text-align:center;\">540000</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">540000</td></tr></table></div></div>", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT"}, {"id": "objective>Accounts>1999>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information to answer the question below <br/> Aminu and Sons credit purchases (Extract) as at February 1996. <br/>  <br/> Feb 1Credit balances---------------- 40, 000 <br/> Debit balances -----------------------1, 000 <br/> Feb 28 Purchases journal totals--------------------- 500,000 <br/> Returns outwards journal totals ----------------------50,000 <br/> Cheques paid to suppliers -------------------400,000 <br/> Promissory notes sent to suppliers------------- 30,000 <br/> Discount received from suppliers............................8,000 <br/> Credit balance in the purchases ledger set off against debit balances in the sales ledger-------2,000 <br/> What is the balance c/d in the purchases ledger control account?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#2, 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#8, 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#40, 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#49, 000</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trade Payable Account <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> #</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">#</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Bal b/f </td><td style=\"border:1px solid black;text-align:center;\"> 1000</td><td style=\"border:1px solid black;text-align:center;\"> Bal b/f</td><td style=\"border:1px solid black;text-align:center;\">40000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Returns outwards</td><td style=\"border:1px solid black;text-align:center;\"> 50000</td><td style=\"border:1px solid black;text-align:center;\"> Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 500000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cheques paid to supplier</td><td style=\"border:1px solid black;text-align:center;\"> 400000</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Promissory note</td><td style=\"border:1px solid black;text-align:center;\"> 30000</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Discount received from suppliers</td><td style=\"border:1px solid black;text-align:center;\">8000</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Set off</td><td style=\"border:1px solid black;text-align:center;\"> 2000</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Bal c/d (missing figure) </td><td style=\"border:1px solid black;text-align:center;\"><span style=\"text-decoration:underline;\"> 49000 </span></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Total</td><td style=\"border:1px solid black;text-align:center;\">540000</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">540000</td></tr></table></div></div>", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT"}, {"id": "objective>Accounts>1999>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Total cash received from debtors</td><td style=\"border:1px solid black;text-align:center;\"> 30000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Total purchases for the period </td><td style=\"border:1px solid black;text-align:center;\">21000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Amount owed by debtors at the beginning of the period </td><td style=\"border:1px solid black;text-align:center;\">4000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Equipment bought</td><td style=\"border:1px solid black;text-align:center;\"> 2500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Amount owed by debtors at the end of the period </td><td style=\"border:1px solid black;text-align:center;\">3000</td></tr></table></div> <br/> Determine the value of sales for the period</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N29,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N 31,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N46,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N50,000</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sales ledger control Account <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> #</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">#</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Bal b/f</td><td style=\"border:1px solid black;text-align:center;\"> 4000</td><td style=\"border:1px solid black;text-align:center;\"> Bal c/d</td><td style=\"border:1px solid black;text-align:center;\"> 3000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales ( missing figure)</td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"text-decoration:underline;\"> 29000 </span></td><td style=\"border:1px solid black;text-align:center;\">Cash received</td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"text-decoration:underline;\"> 30000 </span></td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> 33000</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">33000</td></tr></table></div></div>", "topic": "ACCOUNTING RATIO (2) : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO"}, {"id": "objective>Accounts>1999>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the factory cost of production has been ascertained, manufactured goods are transferred to trading account by?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debiting manufacturing account and crediting trading account</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> crediting sales account and debiting trading account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debiting sales account and crediting trading account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crediting manufacturing account and debiting trading account</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturing Account: Tracks all production costs incurred, including materials, labor, and overheads. <br/>  <br/> Trading Account: Summarizes the cost of goods sold (COGS) and sales revenue. <br/>  <br/> Transferring Manufactured Goods: Once production costs are finalized in the manufacturing account, the cost of goods manufactured (COGM) is transferred to the trading account. <br/>  <br/> Debiting the manufacturing account reduces its balance, recognizing the completion of production costs. <br/>  <br/> Crediting the trading account reflects an increase in the cost of goods available for sale. <br/>  <br/> This approach aligns with standard accounting principles, ensuring accurate reflection of costs and revenues in both accounts.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>1999>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Lawal and co makes blocks and sell to builders. In computing prime cost, which of the following costs would be considered appropriate?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cement, sand and carriage outwards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water ,carriage inwards and cement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sales boys'wages, cement and sand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carriage outwards,carriage inwards and cement</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carriage inwards is the cost incurred in transportation of raw materials and consumables from procurements site to the factory where it is finally consumed.  <br/>  <br/> The prime cost is the expenditure directly charged to a particular unit and it is calculated as: <br/>  Prime cost = Opening stock of RM + Purchases of RM + Carriage inwards - Closing stock of RM + Direct labour + Direct expenses + Direct materials.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>1999>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturing costs can be classified based on?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">timing of charges degree of averaging and size of capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">degree of averaging, ease of traceability and timing of charges</div>", "<div style=\"font-family:Cambria;font-size:17px;\">degree of averaging, size of floor space occupied and cost accounts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">number of employees, timing of charges and management style</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturing costs can be classified based on the degree of averaging (how costs are spread over units produced), ease of traceability (how easily a cost can be assigned to a product), and timing of charges (when the cost is recognized). The size of floor space occupied, number of employees, and management style are not standard bases for classifying manufacturing costs.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>1999>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between the factory cost of production and the prime cost of production is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">direct materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">selling expenses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">overhead</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The prime cost of production is the direct cost of producing goods or services. It includes direct materials and direct labour. The factory cost of production, on the other hand, includes the prime cost plus overheads. Therefore, the difference between the factory cost of production and the prime cost of production is the overhead.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>1999>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Receipt and payments account of a non-profit making organization is principally a summary of the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bank entries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash book entries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expenditure entries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance sheet entries</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The receipt and payment account is the summary of cash and bank transactions which helps in the preparation of income and expenditure account and the balance sheet.</div>", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS"}, {"id": "objective>Accounts>1999>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Club debtors at start</td><td style=\"border:1px solid black;text-align:center;\"> N150</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cash sales </td><td style=\"border:1px solid black;text-align:center;\">N4850</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Club debtors at close </td><td style=\"border:1px solid black;text-align:center;\">N900</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cash received from debtors </td><td style=\"border:1px solid black;text-align:center;\">N550</td></tr></table></div> <br/> What is the amount of club sales?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N6,150</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N4,850</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N4,650</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N1,300</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Purchases ledger control Account <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> #</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">#</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Bal b/f</td><td style=\"border:1px solid black;text-align:center;\"> 150</td><td style=\"border:1px solid black;text-align:center;\">Bal c/d</td><td style=\"border:1px solid black;text-align:center;\"> 900</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Credit sales </td><td style=\"border:1px solid black;text-align:center;\"> 1300</td><td style=\"border:1px solid black;text-align:center;\"> Cash from debtors</td><td style=\"border:1px solid black;text-align:center;\"> 550</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> 1450</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">1450</td></tr></table></div> <br/>  <br/> Club sales = Cash sales + Credit sales <br/>  = 1300 + 4850 <br/> = #6,150</div>", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS"}, {"id": "objective>Accounts>1999>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A credit balance on a receipt and payments account indicates that the non-profit making organization?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">had more revenues than expenses during the period</div>", "<div style=\"font-family:Cambria;font-size:17px;\">did not owe much liabilities during the period</div>", "<div style=\"font-family:Cambria;font-size:17px;\">received more cash than it paid out during the period</div>", "<div style=\"font-family:Cambria;font-size:17px;\">made more cash payments than it received during the period</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A receipt and payments account is a summary of cash inflows (receipts) and cash outflows (payments) for a non-profit organization during a specific period. <br/> A credit balance in this account signifies that the total of the \"receipts\" column is greater than the total of the \"payments\" column. <br/> This indicates that the organization received more cash than it paid out during the period.</div>", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS"}, {"id": "objective>Accounts>1999>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Goodwill can be valued in partnership when?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a partners make profits</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> large losses are made</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> a partner retires</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a new branch is opened</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The conditions under which goodwill is valued in a partnership are: <br/> - on the admission of a new partner <br/> - change in the profit and loss sharing ratio <br/> - on the retirement of a partner <br/> - on amalgamation of partnership <br/> - on dissolution of a partnership <br/> - on the death of a partner <br/> - takeover of a partnership by another business or purchase of a partnership by another business <br/> - on the resignation of a partner</div>", "topic": "GOODWILL ACCOUNTS : INTRODUCTION AND REASONS FOR GOODWILL"}, {"id": "objective>Accounts>1999>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">As part of the initial investment, a partner contributes office equipment that originally cost N20,000 and on which provision for depreciation of N12,500 had been recorded. If the partners agree on a valuation of N9,000 for the equipment, what amount should be debited to the office equipment account?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N7,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N9,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N12,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N20,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question states that the partners agreed on a valuation of N9,000 for the equipment. This means that the office equipment account should be debited with the agreed value, which is N9,000. The original cost and the provision for depreciation are irrelevant in this case because the partners have agreed on a different value for the equipment.</div>", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR"}, {"id": "objective>Accounts>1999>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a partner makes a drawing of stock items from a partnership, the accounting impact of the drawing is to increase the partner's?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">goodwill account balance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">current account credit balance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">current account debit balance</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> profit and loss credit balance</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To the firm it is an income and therefore the capital or current accounts of the partners are debited and interest on drawing account is credited.</div>", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR"}, {"id": "objective>Accounts>1999>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Appropriation Account <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> Kudu</td><td style=\"border:1px solid black;text-align:center;\"> Wale</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> #</td><td style=\"border:1px solid black;text-align:center;\"> #</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Interest on capital</td><td style=\"border:1px solid black;text-align:center;\"> 750</td><td style=\"border:1px solid black;text-align:center;\"> 550</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Salaries</td><td style=\"border:1px solid black;text-align:center;\"> 800</td><td style=\"border:1px solid black;text-align:center;\"> 600</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Share of profits</td><td style=\"border:1px solid black;text-align:center;\"> 3300</td><td style=\"border:1px solid black;text-align:center;\"> 3300</td></tr></table></div> <br/> Determine the net profit of the partnership.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N 9,300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N 6,600</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N4,850</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N 4,450</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Net profit = Interest on capital + salaries + share of profits <br/> =   (750 + 550) + ( 800 + 600)+ ( 3,300 + 3,300) <br/> = #9,300</div>", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR"}, {"id": "objective>Accounts>1999>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Dele and Seun who are in partnership, have decided to covert their business into a limited liability company where both become directors. To convert the business?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">they will simply continue since there are no new members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the partnership is formally ended and new company books opened</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the shares and all other items will be shared equally and not in their former ratios</div>", "<div style=\"font-family:Cambria;font-size:17px;\">computation of goodwill must be done as it is legally required</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The partnership is formally ended and new company books opened when their business is converted into a limited liability company </div>", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY"}, {"id": "objective>Accounts>1999>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a sole proprietorship is purchased for cash, then?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the purchaser debits his business purchase account with the consideration he pays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all assets and liabilities must be bought</div>", "<div style=\"font-family:Cambria;font-size:17px;\">goodwill results where value of assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the vendor debits his business purchase account with the consideration he receives</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the sole proprietorship business is purchased, the  purchaser debits his business purchase account with the consideration he pays.</div>", "topic": "PURCHASES OF BUSINESS : ENTRIES IN THE BOOK OF THE PURCHASER"}, {"id": "objective>Accounts>1999>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The market price per ordinary share of a corporation listed on the stock exchange is most closely related to its?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">earning per share</div>", "<div style=\"font-family:Cambria;font-size:17px;\">redemption price per share</div>", "<div style=\"font-family:Cambria;font-size:17px;\">book value per share</div>", "<div style=\"font-family:Cambria;font-size:17px;\">call price per share</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The market price per ordinary share of a corporation listed on the stock exchange is most closely related to its earnings per share (EPS). EPS is a financial ratio, which divides net earnings available to common shareholders by the average outstanding shares over a certain period of time. The EPS is a per-share profit measure, and the market often uses it to determine a company's profitability. Therefore, it is closely related to the market price of the share.</div>", "topic": "ACCOUNTING RATIO (2) : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO"}, {"id": "objective>Accounts>1999>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following events increases a corporation's shareholders equity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Donation of shares out of the corporation's own stock to the corporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The corporation's purchase of treasury stock</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shares of previously subscribed stock issue to subscribing stockholders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A municipality donation of land to the corporation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A corporation's shareholders' equity increases when the corporation receives a donation of land from a municipality. Shareholders' equity represents the net value of a company, meaning its total assets minus its total liabilities. When a corporation receives a donation, such as land, it increases the total assets of the corporation without increasing its liabilities, thereby increasing the shareholders' equity.</div>", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES"}, {"id": "objective>Accounts>1999>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer the question below <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> N </td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> N</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Paid-up capital</td><td style=\"border:1px solid black;text-align:center;\"> 200000</td><td style=\"border:1px solid black;text-align:center;\"> Fixed assets</td><td style=\"border:1px solid black;text-align:center;\"> 300000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Share premium </td><td style=\"border:1px solid black;text-align:center;\">15000</td><td style=\"border:1px solid black;text-align:center;\">  </td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Profit & loss a/c</td><td style=\"border:1px solid black;text-align:center;\"> 60000</td><td style=\"border:1px solid black;text-align:center;\"> investments</td><td style=\"border:1px solid black;text-align:center;\"> 180000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Long-term loan</td><td style=\"border:1px solid black;text-align:center;\"> 180000</td><td style=\"border:1px solid black;text-align:center;\"> stock</td><td style=\"border:1px solid black;text-align:center;\"> 28000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> Debtors</td><td style=\"border:1px solid black;text-align:center;\"> 90000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Creditors</td><td style=\"border:1px solid black;text-align:center;\"> 200000</td><td style=\"border:1px solid black;text-align:center;\"> Provision(3000)</td><td style=\"border:1px solid black;text-align:center;\"> 87000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Other current</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> Cash</td><td style=\"border:1px solid black;text-align:center;\"> 60000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">liabilities</td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"text-decoration:underline;\"> 100000 </span></td><td style=\"border:1px solid black;text-align:center;\"> bank</td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"text-decoration:underline;\"> 10000 </span></td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"text-decoration:underline;\"> 755000 </span></td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"text-decoration:underline;\"> 755000 </span></td></tr></table></div> <br/>  <br/> The quick ratio is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.82: 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.91:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.95:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:53:1</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Quick ratio = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">Current assets - Closing stock ( inventory)</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> Current liabilities</span> <br/>  <br/> Current assets = 28,000 + 90,000 + 87,000 + 60,000+10,000 <br/> = 275,000 <br/>  <br/> Current liabilities = 200,000 + 100,000 <br/> = 300,000 <br/>  <br/> Quick ratio = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">275,000 - 28,000</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">300,000</span> <br/>  <br/> = 0.82 : 1</div>", "topic": "ACCOUNTING RATIO (2) : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO"}, {"id": "objective>Accounts>1999>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer the question below <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> N </td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> N</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Paid-up capital</td><td style=\"border:1px solid black;text-align:center;\"> 200000</td><td style=\"border:1px solid black;text-align:center;\"> Fixed assets</td><td style=\"border:1px solid black;text-align:center;\"> 300000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Share premium </td><td style=\"border:1px solid black;text-align:center;\">15000</td><td style=\"border:1px solid black;text-align:center;\">  </td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Profit & loss a/c</td><td style=\"border:1px solid black;text-align:center;\"> 60000</td><td style=\"border:1px solid black;text-align:center;\"> investments</td><td style=\"border:1px solid black;text-align:center;\"> 180000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Long-term loan</td><td style=\"border:1px solid black;text-align:center;\"> 180000</td><td style=\"border:1px solid black;text-align:center;\"> stock</td><td style=\"border:1px solid black;text-align:center;\"> 28000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> Debtors</td><td style=\"border:1px solid black;text-align:center;\"> 90000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Creditors</td><td style=\"border:1px solid black;text-align:center;\"> 200000</td><td style=\"border:1px solid black;text-align:center;\"> Provision(3000)</td><td style=\"border:1px solid black;text-align:center;\"> 87000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Other current</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> Cash</td><td style=\"border:1px solid black;text-align:center;\"> 60000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">liabilities</td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"text-decoration:underline;\"> 100000 </span></td><td style=\"border:1px solid black;text-align:center;\"> bank</td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"text-decoration:underline;\"> 10000 </span></td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"text-decoration:underline;\"> 755000 </span></td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"text-decoration:underline;\"> 755000 </span></td></tr></table></div> <br/> Determine the owners equity</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> N200,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N 215,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N275,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N755,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Owner's equity = Paid up capital + Share premium + Profit &loss  <br/> = 200,000 + 15,000 +60,000 <br/> = #275,000</div>", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES"}, {"id": "objective>Accounts>1999>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a promoter pays a lawyer N5,000 for services rendered in preparing a Memorandum of Incorporation, the journal entry is to debit?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">preliminary expenses, credit cash accounts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promoter, credit creditors' accounts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lawyer's credit cash accounts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash , credit incorporation accounts</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a promoter pays for services rendered in preparing a Memorandum of Incorporation, it is considered as a preliminary expense. Preliminary expenses are the costs incurred before a company is formed. These costs are debited to the preliminary expenses account and credited to the cash account, as cash is going out of the business.</div>", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY"}, {"id": "objective>Accounts>1999>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calls in advance are treated in the balance sheet as?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">current asset</div>", "<div style=\"font-family:Cambria;font-size:17px;\">current liability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed liability</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Call in advance is an amount which is excess paid by shareholders against which the cells are not yet due. Calls in advance is a current liability.</div>", "topic": "ISSUES OF SHARES : CALLS IN ARREARS AND FORFEITURE OF SHARES"}, {"id": "objective>Accounts>1999>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Shares issued to a vendor in payment of business purchased would require a debit to?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cash account and credit to share capital account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">share capital account and credit to vendor's account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vendor's account and credit to share capital account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">share capital account and credit to cash account</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When shares are issued to a vendor in payment for a business purchased, the vendor's account is debited because the vendor is the receiver of the shares. The share capital account is credited because the company's share capital increases as a result of issuing shares. This follows the double-entry bookkeeping principle where every debit has a corresponding credit.</div>", "topic": "ISSUES OF SHARES : SHARES ISSUED PAYABLE BY INSTALMENTS"}, {"id": "objective>Accounts>1999>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The best method of allocating expenses among departments is to?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">allocate expenses to each department in proportion to the sales of that department</div>", "<div style=\"font-family:Cambria;font-size:17px;\">charge against each department those costs which are within its control</div>", "<div style=\"font-family:Cambria;font-size:17px;\">charge expenses against each department in proportion to the purchases of that department</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allocate expenses to each section of the department in relation to the number of people</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Expenses can be allocated using the direct method i.e allocates costs of each of the service departments to each operating department based on each department's share of the allocation base. </div>", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES"}, {"id": "objective>Accounts>1999>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To record the transfer of stock from one department to another, the correct entry would be to debit?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">goods outwards and credit goods inwards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">merchandise account and credit department stock account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">department transfering and credit department receiving</div>", "<div style=\"font-family:Cambria;font-size:17px;\">department receiving and credit department transfering</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The journal entry for inter-departmental follows: <br/> debit receiving department and credit the transfering department</div>", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES"}, {"id": "objective>Accounts>1999>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to Answer questions below <br/> Among Limited invoiced goods at a cost of N10,000 to its Ikeja branch at a marginal of 20%. The branch later returned goods worth N1,200 at invoice price to the head office. <br/>  <br/> The profit marginal should be?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debit to goods sent to branch account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit to branch stock adjustment account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit to branch adjustment account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit to branch stock adjustment account</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">20</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">100 </span> = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5</span> <br/>  <br/> <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5</span>  x 10,000 <br/>  <br/> Profit = 2000 will be credited to the branch stock adjustment account. <br/>  <br/> Note that: Branch stock adjustment is used to ascertain the gross profit of the branch</div>", "topic": "BRANCH ACCOUNTING : BRANCH ADJUSTMENT METHOD"}, {"id": "objective>Accounts>1999>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to Answer questions below <br/> Among Limited invoiced goods at a cost of N10,000 to its Ikeja branch at a marginal of 20%. The branch later returned goods worth N1,200 at invoice price to the head office. <br/> What is the correct entry in the head office books at the point of initial transfer of the goods?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Branch stock account would be credited with #10,800</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Branch stock account would be debited with N12,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Goods sent to branch account would be debited with N10,800</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Goods sent to branch account would be credited with N12,000</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">20</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">100 </span> = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5</span> <br/>  <br/> <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5</span>  x 10,000 <br/>  <br/> Profit = 2000 <br/>  <br/>  Goods sent to the office = 10,000 + 2000 <br/> = #12,000 credited to the branch account</div>", "topic": "BRANCH ACCOUNTING : BRANCH ADJUSTMENT METHOD"}, {"id": "objective>Accounts>1999>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Capital and revenue expenditures of government are usually accounted for under funds which include?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A personal advances, technical and public funds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">technical, special trust and commercial funds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">personal advances, treasury clearance and special trust funds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercial loans and treasury clearance funds</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capital and revenue expenditures of government are usually accounted for under various funds. These include technical, special trust and commercial funds. Technical funds are used for specific technical projects, special trust funds are used for specific purposes that the government is entrusted with, and commercial funds are used for commercial activities that the government is involved in. Hence, 'technical, special trust and commercial funds' is the correct option.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING"}, {"id": "objective>Accounts>1999>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following account is kept by local governments in Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Balance sheet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Advances account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Debtors account</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Profit and loss account</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Advances account of funds is any advance made on a future commitment or payment. The local government is responsible for keeping this kind of account.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING"}, {"id": "objective>Accounts>1999>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The conventional sources of public revenue includes?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">loans,taxation, foreign reserves and dividends</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest, royalties, taxation and loans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crude oil, interest, posted price and taxation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">taxation, deficit budgeting, royalties and loans </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The conventional sources of public revenue include 'taxation, deficit budgeting, royalties and loans'. Taxation is a mandatory financial charge imposed by a government on its citizens to fund public expenditures. Deficit budgeting occurs when government's expenditures exceed its revenues, creating a deficit that must be funded by borrowing. Royalties are payments made to the government for the right to extract natural resources. Loans are borrowed funds that the government must repay with interest.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE"}];
